
.popup {
  width: 100%;
  height: 100%;
  position: relative;
}
.popup-item {
  width: 80px;
  height: 50px;
  line-height:50px;
  text-align: center;
  color: #fff;
  background: #311b92;
  position: absolute;
  cursor: pointer;
}
.leftTop {
  top: 0;
  left: 0;
}
.rightTop {
  top: 0;
  right: 0;
}
.center {
  top: 50%;
  left: 50%;
  margin-top: -25px;
  margin-left: -40px;
}
.leftBottom{
  bottom: 0;
  left: 0;
}
.rightBottom{
  bottom: 0;
  right: 0;
}



