
.vue-popup {
  position: fixed;
  z-index: 1999;
}
.vue-popup-off {
  border: none;
  outline: none;
  position: absolute;
  top: 0;
  right: 0;
  text-align: center;
  font-size: 12px;
  width: 30px;
  height: 40px;
  color: #7d7d7d;
  background: #fff;
  -webkit-transform: scale(0.85);
          transform: scale(0.85);
  cursor: pointer;
}
.vue-popup-off:hover {
   color: #35a092
}
.vue-popup-container {
  border-radius: 3px;
  box-shadow: 0 1px 8px 0 rgba(0, 0, 0, .5);
  position: absolute;
  z-index: 1999;
  background: #fff;
}
.vue-popup-click-outside-layer {
  top: 0;
  left: 0;
  position: fixed;
  width: 100vw;
  height: 100vh;
  background: transparent;
  cursor: default;
  z-index: 1998;
}
.fade-enter-active,
.fade-leave-active {
  transition: opacity .5s
}
.fade-enter,
.fade-leave-active {
  opacity: 0
}



